import time
import threading
from collections import deque

rate_limits = {}
lock = threading.Lock()

def check_rate_limit(client_ip, max_requests=100, window_seconds=60):
    now = time.time()
    with lock:
        if client_ip not in rate_limits:
            rate_limits[client_ip] = deque()

        window_start = now - window_seconds
        while rate_limits[client_ip] and rate_limits[client_ip][0] < window_start:
            rate_limits[client_ip].popleft()

        if len(rate_limits[client_ip]) >= max_requests:
            return False

        rate_limits[client_ip].append(now)
        return True

def get_remaining(client_ip, max_requests=100, window_seconds=60):
    now = time.time()
    with lock:
        if client_ip not in rate_limits:
            return max_requests
        window_start = now - window_seconds
        count = sum(1 for t in rate_limits[client_ip] if t >= window_start)
        return max(0, max_requests - count)

def reset_client(client_ip):
    with lock:
        rate_limits.pop(client_ip, None)

def reset_all():
    with lock:
        rate_limits.clear()

def get_all_clients():
    with lock:
        return list(rate_limits.keys())
